const body = $input.first().json.body ?? $input.first().json;
const queryParams = $input.first().json.query ?? {};

// pr_id can come from query param (link click) or body (form/API submission)
const pr_id = body.pr_id ?? queryParams.pr_id;
const supplier_email = body.supplier_email ?? queryParams.supplier ?? body.from_email;

if (!pr_id) throw new Error('Missing pr_id in supplier response');
if (!supplier_email) throw new Error('Missing supplier_email in supplier response');

return [{
  json: {
    pr_id,
    supplier_email,
    supplier_name: body.supplier_name ?? 'Unknown Supplier',
    response_type: body.response_type ?? 'quote',
    total_price: body.total_price ? parseFloat(body.total_price) : null,
    currency: body.currency ?? 'EUR',
    delivery_days: body.delivery_days ? parseInt(body.delivery_days) : null,
    payment_terms: body.payment_terms ?? null,
    validity_days: body.validity_days ? parseInt(body.validity_days) : 30,
    notes: body.notes ?? null,
    has_attachment: body.has_attachment ?? false,
    attachment_name: body.attachment_name ?? null,
    received_at: new Date().toISOString()
  }
}];

const agentResponse = $input.first().json;
const parsedResponse = $('Parse Supplier Response').first().json;

// Check if agent says all suppliers have responded
const allResponded = agentResponse.all_suppliers_responded ?? false;

return [{
  json: {
    pr_id: parsedResponse.pr_id,
    supplier_email: parsedResponse.supplier_email,
    all_suppliers_responded: allResponded,
    responses_received: agentResponse.responses_received ?? 1,
    responses_expected: agentResponse.responses_expected ?? 'unknown',
    category_manager_email: agentResponse.category_manager_email ?? null
  }
}];
